/// <summary>
/// 
/// </summary>
public void write()
{
    next write();

    if(curExt() == "O014")
    {
        PurchLine line, purchLine;
        PurchTable header, headerUpd, currentHeader;
        FormDataSource fds, fdsHeader;

        line      = this.cursor();
        header    = line.purchTable();
        fdsHeader = this.formRun().dataSource(formDataSourceStr(PurchTable, PurchTable));

        if(line.DefaultDimension != header.DefaultDimension)
        {
            select firstonly RecId from purchLine order by LineNumber asc
                where purchLine.PurchId == header.PurchId;
            if(purchLine.RecId == line.RecId)
            {
                DialogButton diagBut;

                str strMessage = 'Do you want to copy financial dimension from line to header?';
                str strTitle   = 'Copy financial dimension';

                diagBut = Box::yesNo(strMessage, DialogButton::No, strTitle);

                if(diagBut == DialogButton::Yes)
                {
                    PurchId currentPurchId =  header.PurchId;
                    ttsBegin;
                    header.skipDataMethods(true);
                    header.selectForUpdate(true);
                    header.DefaultDimension = line.DefaultDimension;
                    header.doUpdate();
                    ttsCommit;
                    fdsHeader.reread();
                    fdsHeader.research(true);

                    currentHeader = PurchTable::find(currentPurchId);
                    fdsHeader.findRecord(currentHeader);

                    Info("Financial dimesnions has been copied to header.");

                }

            }

        }
    }
}
